    double findMaxAverage1(vector<int>& nums, int k) {
        double sum = 0;
        double maxAvg = numeric_limits<double>::lowest();

        for(int i = 0; i < nums.size(); i++) {

            if(i > k-1) sum -= nums[i-k];

            sum += nums[i];

            double avg = (sum / k);
            if(maxAvg < avg && i >= k-1) maxAvg = avg;
        }

        return maxAvg;
    }

    double findMaxAverage2(vector<int>& nums, int k) {
        int n = nums.size();

        double maxAvg = -1e16;
        double sum = 0;
        
        int i = 0, j = 0;

        while(j < n) {
            sum += nums[j];

            if(j-i+1 >= k) {
                maxAvg = max(maxAvg, sum/k);
                sum -= nums[i];
                i++;
            }
            j++;
        }

        return maxAvg;
    }
